const text = $json.text || '';
const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
const sectorIdx = lines.findIndex(l => /^Sector:/i.test(l));
const companyName = sectorIdx > 0 ? lines[sectorIdx - 1] : (lines[0] || 'Unknown Company');
const quarterMatch = text.match(/Quarter\s+ended\s+(\d{1,2}\s+[A-Za-z]+\s+\d{4})/i);
const quarterLabel = quarterMatch ? quarterMatch[1].replace(/\s+/g, ' ').trim() : 'Current Quarter';
const reportDate = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });

const monthNames = ['january','february','march','april','may','june','july','august','september','october','november','december'];
const qMatch = quarterLabel.match(/(\d{1,2})\s+([A-Za-z]+)\s+(\d{4})/);
let quarterFolderName = 'Unfiled';
if (qMatch) {
  const monthIdx = monthNames.indexOf(qMatch[2].toLowerCase());
  if (monthIdx >= 0) {
    const q = Math.floor(monthIdx / 3) + 1;
    quarterFolderName = 'Q' + q + '-' + qMatch[3];
  }
}

return [{ json: { text, companyName, quarterLabel, reportDate, quarterFolderName } }];

const res = $input.first().json;
const raw = (res.content && res.content[0] ? res.content[0].text : '').trim();

function safeParse(text) {
  let cleaned = text.trim();
  const fenceMatch = cleaned.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenceMatch) cleaned = fenceMatch[1].trim();
  try { return JSON.parse(cleaned); } catch (e) { return null; }
}

const parsed = safeParse(raw) || {};
const draftParagraph = parsed.draftParagraph || raw;
const kpiRows = Array.isArray(parsed.kpiRows) ? parsed.kpiRows : [];
const revenueTrend = parsed.revenueTrend && Array.isArray(parsed.revenueTrend.quarters) ? parsed.revenueTrend : { quarters: [], values: [] };
const marginTrend = parsed.marginTrend && Array.isArray(parsed.marginTrend.quarters) ? parsed.marginTrend : { quarters: [], values: [] };
const segments = parsed.segments && Array.isArray(parsed.segments.labels) ? parsed.segments : { labels: [], values: [] };
const watchItems = Array.isArray(parsed.watchItems) ? parsed.watchItems : [];

return [{
  json: {
    draftParagraph,
    kpiRows,
    revenueTrend,
    marginTrend,
    segments,
    watchItems,
    sourceText: $('Parse Report Metadata').item.json.text,
    companyName: $('Parse Report Metadata').item.json.companyName,
    quarterLabel: $('Parse Report Metadata').item.json.quarterLabel,
    reportDate: $('Parse Report Metadata').item.json.reportDate,
    quarterFolderName: $('Parse Report Metadata').item.json.quarterFolderName
  }
}];

const res = $input.first().json;
const finalParagraph = (res.content && res.content[0] ? res.content[0].text : '').trim();
const draft = $('Parse Draft Response').item.json;
return [{
  json: {
    finalParagraph,
    companyName: draft.companyName,
    quarterLabel: draft.quarterLabel,
    reportDate: draft.reportDate,
    quarterFolderName: draft.quarterFolderName,
    kpiRows: draft.kpiRows,
    revenueTrend: draft.revenueTrend,
    marginTrend: draft.marginTrend,
    segments: draft.segments,
    watchItems: draft.watchItems
  }
}];

const isNew = !$json.files;
const docId = $json.files ? $json.files[0].id : $json.id;
return [{ json: { docId, isNew } }];

