const p = $('Parse Final Paragraph').item.json;
const sep = String.fromCharCode(8211);

const SLATE = '#44546A';
const SLATE_LIGHT = '#8496B0';
const GRID = '#E8EAEF';

function lineChartUrl(labels, values, label, color) {
  const config = {
    type: 'line',
    data: { labels, datasets: [{ label, data: values, borderColor: color, fill: false, pointRadius: 2, borderWidth: 2, lineTension: 0 }] },
    options: {
      legend: { display: false },
      title: { display: true, text: label, fontColor: SLATE, fontSize: 14 },
      scales: {
        xAxes: [{ gridLines: { display: false }, ticks: { fontColor: SLATE } }],
        yAxes: [{ gridLines: { color: GRID }, ticks: { fontColor: SLATE } }]
      }
    }
  };
  return 'https://quickchart.io/chart?width=480&height=240&backgroundColor=white&c=' + encodeURIComponent(JSON.stringify(config));
}

function barChartUrl(labels, values, label) {
  const config = {
    type: 'bar',
    data: { labels, datasets: [{ label, data: values, backgroundColor: SLATE }] },
    options: {
      legend: { display: false },
      title: { display: true, text: label, fontColor: SLATE, fontSize: 14 },
      scales: {
        xAxes: [{ gridLines: { display: false }, ticks: { fontColor: SLATE } }],
        yAxes: [{ gridLines: { color: GRID }, ticks: { fontColor: SLATE } }]
      }
    }
  };
  return 'https://quickchart.io/chart?width=520&height=240&backgroundColor=white&c=' + encodeURIComponent(JSON.stringify(config));
}

let revenueChartUrl = '';
if (p.revenueTrend && p.revenueTrend.quarters && p.revenueTrend.quarters.length) {
  revenueChartUrl = lineChartUrl(p.revenueTrend.quarters, p.revenueTrend.values, 'Revenue (EUR M)', SLATE);
}

let marginChartUrl = '';
if (p.marginTrend && p.marginTrend.quarters && p.marginTrend.quarters.length) {
  marginChartUrl = lineChartUrl(p.marginTrend.quarters, p.marginTrend.values, 'EBITDA Margin (%)', SLATE_LIGHT);
}

let segmentChartUrl = '';
if (p.segments && p.segments.labels && p.segments.labels.length) {
  segmentChartUrl = barChartUrl(p.segments.labels, p.segments.values, 'Revenue by Segment (%)');
}

const header = p.companyName + ' ' + sep + ' ' + p.quarterLabel;

return [{ json: {
  header,
  headerText: header + '\n\n',
  narrative: p.finalParagraph,
  revenueChartUrl,
  marginChartUrl,
  segmentChartUrl,
  hasKpi: (p.kpiRows || []).length > 0,
  hasWatch: (p.watchItems || []).length > 0
} }];

const doc = $json;
const p = $('Parse Final Paragraph').item.json;
const b = $('Build Section Content').item.json;

const tables = [];
(doc.body.content || []).forEach((el) => { if (el.table) tables.push(el); });
const insertedCount = (b.hasKpi ? 1 : 0) + (b.hasWatch ? 1 : 0);
const lastTables = tables.slice(tables.length - insertedCount);

let idx = 0;
let kpiTable = null, watchTable = null;
if (b.hasKpi) { kpiTable = lastTables[idx]; idx++; }
if (b.hasWatch) { watchTable = lastTables[idx]; idx++; }

const fills = [];
function addFills(tableEl, header, rows) {
  const allRows = [header, ...rows];
  allRows.forEach((rowVals, r) => {
    header.forEach((_, c) => {
      const text = String((rowVals || [])[c] ?? '').trim();
      if (!text) return;
      const cell = tableEl.table.tableRows[r].tableCells[c];
      fills.push({ startIndex: cell.content[0].startIndex, text });
    });
  });
}
if (kpiTable) addFills(kpiTable, ['KPI', 'This Quarter', 'Prior Quarter', 'Change'], p.kpiRows);
if (watchTable) addFills(watchTable, ['Item', 'Status', 'Note'], p.watchItems.map((w) => [w.item, w.status, w.note]));

// Descending order: each insert never shifts a position that is still pending.
fills.sort((a, c) => c.startIndex - a.startIndex);
const requests = fills.map((cf) => ({ insertText: { text: cf.text, location: { index: cf.startIndex } } }));

return [{ json: { requests, docId: $('Normalize Doc Id').item.json.docId } }];

const doc = $json;
const p = $('Parse Final Paragraph').item.json;
const b = $('Build Section Content').item.json;

const SLATE = { red: 0.267, green: 0.329, blue: 0.416 };
const WHITE = { red: 1, green: 1, blue: 1 };
const RED = { red: 0.69, green: 0.0, blue: 0.125 };
const AMBER = { red: 0.72, green: 0.53, blue: 0.04 };
const GREEN = { red: 0.11, green: 0.48, blue: 0.24 };

const tables = [];
(doc.body.content || []).forEach((el) => { if (el.table) tables.push(el); });
const insertedCount = (b.hasKpi ? 1 : 0) + (b.hasWatch ? 1 : 0);
const lastTables = tables.slice(tables.length - insertedCount);

let idx = 0;
let kpiTable = null, watchTable = null;
if (b.hasKpi) { kpiTable = lastTables[idx]; idx++; }
if (b.hasWatch) { watchTable = lastTables[idx]; idx++; }

const requests = [];

// Range of a cell's text content: from first paragraph start to just before the cell end marker.
function cellTextRange(cell) {
  return { startIndex: cell.content[0].startIndex, endIndex: cell.endIndex - 1 };
}

function styleTable(tableEl, numCols) {
  // Uniform 10pt across the whole (already filled) table.
  requests.push({ updateTextStyle: {
    range: { startIndex: tableEl.startIndex, endIndex: tableEl.endIndex },
    textStyle: { fontSize: { magnitude: 10, unit: 'PT' } }, fields: 'fontSize' } });
  // Slate header row background.
  requests.push({ updateTableCellStyle: {
    tableCellStyle: { backgroundColor: { color: { rgbColor: SLATE } } }, fields: 'backgroundColor',
    tableRange: { tableCellLocation: { tableStartLocation: { index: tableEl.startIndex }, rowIndex: 0, columnIndex: 0 }, rowSpan: 1, columnSpan: numCols } } });
  // White bold header text, using each cell's real, settled range.
  tableEl.table.tableRows[0].tableCells.forEach((cell) => {
    const r = cellTextRange(cell);
    if (r.endIndex > r.startIndex) {
      requests.push({ updateTextStyle: { range: r,
        textStyle: { bold: true, foregroundColor: { color: { rgbColor: WHITE } }, fontSize: { magnitude: 10, unit: 'PT' } },
        fields: 'bold,foregroundColor,fontSize' } });
    }
  });
}

if (kpiTable) styleTable(kpiTable, 4);
if (watchTable) {
  styleTable(watchTable, 3);
  // Color-code the Status column by value.
  const statusColors = { 'Attention': RED, 'Monitor': AMBER, 'On Track': GREEN };
  watchTable.table.tableRows.slice(1).forEach((row, i) => {
    const status = (p.watchItems[i] || {}).status;
    const color = statusColors[status];
    if (!color) return;
    const r = cellTextRange(row.tableCells[1]);
    if (r.endIndex > r.startIndex) {
      requests.push({ updateTextStyle: { range: r,
        textStyle: { bold: true, foregroundColor: { color: { rgbColor: color } } },
        fields: 'bold,foregroundColor' } });
    }
  });
}

// Company section header and narrative, located by content search on the settled doc.
function flattenAndFind(needle) {
  const runs = [];
  function walk(elements) {
    for (const el of elements || []) {
      if (el.paragraph && el.paragraph.elements) {
        for (const pe of el.paragraph.elements) {
          if (pe.textRun && typeof pe.textRun.content === 'string') {
            runs.push({ start: pe.startIndex, text: pe.textRun.content });
          }
        }
      }
      if (el.table) {
        for (const row of el.table.tableRows || []) {
          for (const cell of row.tableCells || []) walk(cell.content || []);
        }
      }
    }
  }
  walk(doc.body.content);
  let flat = '';
  const offsets = [];
  for (const r of runs) {
    for (let i = 0; i < r.text.length; i++) offsets.push(r.start + i);
    flat += r.text;
  }
  const foundIdx = flat.lastIndexOf(needle);
  if (foundIdx === -1) return null;
  return { startIndex: offsets[foundIdx], endIndex: offsets[foundIdx + needle.length - 1] + 1 };
}

const docEnd = (doc.body.content && doc.body.content.length)
  ? doc.body.content[doc.body.content.length - 1].endIndex : null;
const headerRange = flattenAndFind(b.header);
if (headerRange && docEnd) {
  const secStart = Math.max(1, headerRange.startIndex - 2);
  const secEnd = Math.max(secStart + 1, docEnd);
  const resetRange = { startIndex: secStart, endIndex: secEnd };
  // Clear inherited list bullets and reset to normal paragraph style across the company section.
  requests.unshift({ deleteParagraphBullets: { range: resetRange } });
  requests.unshift({ updateParagraphStyle: { range: resetRange, paragraphStyle: { namedStyleType: 'NORMAL_TEXT' }, fields: 'namedStyleType' } });
  // Set the Inter font across the whole company section so it matches the template's pages 1-2.
  const fontRange = { startIndex: secStart, endIndex: Math.max(secStart + 1, docEnd - 1) };
  requests.unshift({ updateTextStyle: { range: fontRange, textStyle: { weightedFontFamily: { fontFamily: 'Inter' } }, fields: 'weightedFontFamily' } });
}
if (headerRange) {
  requests.push({ updateTextStyle: { range: headerRange,
    textStyle: { bold: true, foregroundColor: { color: { rgbColor: SLATE } }, fontSize: { magnitude: 15, unit: 'PT' } },
    fields: 'bold,foregroundColor,fontSize' } });
}
const narrativeRange = flattenAndFind(b.narrative);
if (narrativeRange) {
  requests.push({ updateTextStyle: { range: narrativeRange,
    textStyle: { fontSize: { magnitude: 10, unit: 'PT' } }, fields: 'fontSize' } });
}

return [{ json: { requests, docId: $('Normalize Doc Id').item.json.docId } }];
